/* ─── Sub-components ─────────────────────────────────────────── */
function InfoRow({ label, value }) {
  const empty = !value || value === "-" || value === "0" || value === 0;
  return (
    <div className="acv-row">
      <div className="acv-lbl">{label}</div>
      <div className={`acv-val${empty ? " empty" : ""}`}>
        {empty ? "Not provided" : value}
      </div>
    </div>
  );
}

/* ─── Main Component ─────────────────────────────────────────── */
function AdminCompanyView() {
  const [successMessage, setsuccessMessage] = useState("");
  const [activeTab, setActiveTab] = useState("overview");
  const { id } = useParams();
  const apiUrl = API_BASE_URL + "api/admin/company/";
  const [records, setRecords] = useState("");
  const [totalrounds, setTotalrounds] = useState('0');
  const [totalinvestors, setTotalinvestors] = useState('0');
  const [totalraised, setTotalraised] = useState('0');
  const [allinvestment, setAllinvestment] = useState([]);
  const [companyFundinground, setCompanyFundinground] = useState([]);
  const [companyDocument, setCompanyDocument] = useState([]);
  document.title = "Company Profile - Admin";
  const storedUser = localStorage.getItem("adminLogin");
  const userLogin = storedUser ? JSON.parse(storedUser) : null;
  const [loading, setLoading] = useState(true);
  const access_token = userLogin.admintoken;
  const fmtMoney = (v) => {
    const n = parseFloat(v) || 0;
    if (n === 0) return "—";
    if (n >= 1000000) return `${(n / 1000000).toFixed(2)}M`;
    if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
    return `${n.toLocaleString()}`;
  };
  const typePill = {
    "Preferred Equity": "pill pill-blue",
    "Convertible Note": "pill pill-purple",
    "Safe": "pill pill-amber",
    "Common Stock": "pill pill-gray",
    "Equity": "pill pill-blue",
    "Convertible": "pill pill-purple",
    "SAFE": "pill pill-amber",
    "Debt": "pill pill-gray",
  };

  const statusPill = {
    Open: "pill pill-green",
    Closed: "pill pill-gray",
    Draft: "pill pill-amber",
  };
  useEffect(() => {
    getUsercompnayInfo();
    getCompanyTotalRoundInvestor();
    getCompanyAllInvestment();
    getCompanyFundinground();
    getCompanyDocument();
  }, []);

  const getUsercompnayInfo = async () => {
    try {
      const res = await axios.post(apiUrl + "getUsercompnayInfo", { company_id: id }, {
        headers: { Accept: "application/json", "Content-Type": "application/json", access_token: access_token },
      });
      setRecords(res.data.results);
    } catch (err) {
      console.error("Error:", err.message);
    }
  };

  const formatDate = (input) => {
    if (!input) return "—";
    const d = new Date(input); if (isNaN(d)) return input;
    const mo = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const n = d.getDate();
    const s = n >= 11 && n <= 13 ? "th" : ["th", "st", "nd", "rd"][n % 10] || "th";
    return `${mo[d.getMonth()]} ${n}${s}, ${d.getFullYear()}`;
  };
  //Total investor
  const getCompanyTotalRoundInvestor = async () => {
    try {
      const res = await axios.post(apiUrl + "getCompanyTotalRoundInvestor", { company_id: id }, {
        headers: { Accept: "application/json", "Content-Type": "application/json" },
      });

      setTotalrounds(res.data.total_rounds);      // This is for ROUNDS
      setTotalinvestors(res.data.total_investors); // This is for INVESTORS
      setTotalraised(res.data.total_raised);
    } catch (err) {
      console.error("Error:", err.message);
    }
  };
  //All Investor Investment
  const getCompanyAllInvestment = async () => {
    try {
      const res = await axios.post(apiUrl + "getCompanyAllInvestment", { company_id: id }, {
        headers: { Accept: "application/json", "Content-Type": "application/json" },
      });
      setAllinvestment(res.data.results);      // This is for ROUNDS
    } catch (err) {
      console.error("Error:", err.message);
    }
  };

  const getCompanyFundinground = async () => {
    setLoading(true);
    try {
      const res = await axios.post(apiUrl + "getCompanyFundinground", { company_id: id }, {
        headers: { Accept: "application/json", "Content-Type": "application/json" },
      });
      setCompanyFundinground(res.data.results);      // This is for ROUNDS
    } catch (err) {
      console.error("Error:", err.message);
    }
  };
  const getCompanyDocument = async () => {
    try {
      const res = await axios.post(apiUrl + "getCompanyDocument", { company_id: id }, {
        headers: { Accept: "application/json", "Content-Type": "application/json" },
      });
      setCompanyDocument(res.data.results);      // This is for ROUNDS
    } catch (err) {
      console.error("Error:", err.message);
    }
  };
  const stats = [
    { label: "Industry", value: records?.company_industory || "Tech", icon: <Briefcase size={15} />, color: "#ef4444", bg: "#fff5f5" },
    { label: "Employees", value: records?.employee_number || "1-10", icon: <Users size={15} />, color: "#22c55e", bg: "#f0fdf4" },
    {
      label: "Total Raised", value: <CurrencyFormatterAdmin amount={totalraised} currency={companyFundinground[0]?.currency || ""}
        digit={2} />, icon: <DollarSign size={15} />, color: "#6366f1", bg: "#f5f3ff"
    },
    { label: "Incorporated", value: formatDate(records?.year_registration) || "2024", icon: <Calendar size={15} />, color: "#f59e0b", bg: "#fffbeb" },
    { label: "Investors", value: totalinvestors === 0 ? "0" : totalinvestors, icon: <Users size={15} />, color: "#0ea5e9", bg: "#f0f9ff" },
    { label: "Rounds", value: totalrounds === 0 ? "0" : totalrounds, icon: <Layers size={15} />, color: "#10b981", bg: "#ecfdf5" },
  ];

  const tabs = [
    { key: "overview", label: "Overview", icon: <Building2 size={13} /> },
    { key: "investors", label: "Investors", icon: <Users size={13} />, badge: totalinvestors === 0 ? "0" : totalinvestors },
    { key: "rounds", label: "Rounds", icon: <TrendingUp size={13} />, badge: totalrounds === 0 ? "0" : totalrounds },
    { key: "captable", label: "Active Cap Table", icon: <PieChart size={13} /> },
    { key: "documents", label: "Documents", icon: <FolderOpen size={13} />, badge: companyDocument.length },
  ];

  return (
    <>
      <style>{css}</style>
      <div>
        <div className="d-flex align-items-start gap-0">
          <Sidebar />
          <div className="d-flex flex-column gap-0 w-100 dashboard_padding">
            <TopBar />
            <section className="dashboard_adminh">
              <div className="container-xl">
                <div className="row gy-4">
                  <div className="col-12">
                    {successMessage && <SuccessAlert message={successMessage} onClose={() => setsuccessMessage("")} />}

                    {/* Back + Title */}
                    <div className="d-flex align-items-center justify-content-between flex-wrap gap-2 mb-3">
                      <div className="d-flex align-items-center gap-3">
                        <Link to={`/admin/users/company/${records?.user_id}`} className="btn btn-secondary btn-sm d-inline-flex align-items-center gap-2">
                          <FaArrowLeft /> Back
                        </Link>
                        {records?.user_first_name && (
                          <span className="text-muted" style={{ fontSize: 13 }}>
                            Owner: <b className="text-dark">{records.user_first_name} {records.user_last_name}</b>
                          </span>
                        )}
                      </div>
                      <h5 className="mb-0 fw-semibold">Company Profile</h5>
                    </div>

                    {/* Hero Header */}
                    <div className="acv-header">
                      <div className="d-flex align-items-center gap-3 flex-wrap">
                        <div className="acv-avatar">
                          {(records?.company_name?.charAt(0) || "C").toUpperCase()}
                        </div>
                        <div className="flex-grow-1">
                          <h5 className="text-white fw-bold mb-1" style={{ fontSize: 17 }}>
                            {records?.company_name || "Company Name"}
                          </h5>
                          <p className="mb-2" style={{ color: "rgba(255,255,255,.75)", fontSize: 12 }}>
                            {records?.company_industory || "Technology"}
                            {records?.company_city ? ` · ${records.company_city}` : ""}
                          </p>
                          <div className="d-flex flex-wrap gap-2">
                            {records?.company_email && <span className="acv-badge"><Mail size={10} /> {records.company_email}</span>}
                            {records?.phone && <span className="acv-badge"><Phone size={10} /> {records.phone}</span>}
                            {records?.company_country && <span className="acv-badge"><Globe size={10} /> {records.company_country}</span>}
                          </div>
                        </div>
                      </div>
                    </div>

                    {/* Stat Strip */}
                    <div className="row g-3 mb-4">
                      {stats.map((s, i) => (
                        <div key={i} className="col-6 col-md-2">
                          <div className="acv-stat">
                            <div className="acv-stat-icon" style={{ background: s.bg, color: s.color }}>{s.icon}</div>
                            <div className="acv-stat-val">{s.value || "—"}</div>
                            <div className="acv-stat-lbl">{s.label}</div>
                          </div>
                        </div>
                      ))}
                    </div>

                    {/* Tabs */}
                    <div className="acv-tabs">
                      {tabs.map(t => (
                        <button key={t.key} className={`acv-tab${activeTab === t.key ? " active" : ""}`} onClick={() => setActiveTab(t.key)}>
                          {t.icon} {t.label}
                          {t.badge !== undefined && (
                            <span style={{ background: activeTab === t.key ? "#ef4444" : "#f1f5f9", color: activeTab === t.key ? "#fff" : "#64748b", borderRadius: 20, padding: "1px 7px", fontSize: 10, fontWeight: 700, marginLeft: 2 }}>
                              {t.badge}
                            </span>
                          )}
                        </button>
                      ))}
                    </div>

                    <div className="acv-tab-content">

                      {/* ── OVERVIEW TAB ── */}
                      {activeTab === "overview" && (
                        <div className="row g-3">
                          <div className="col-md-6">
                            <div className="acv-card h-100">
                              <div className="acv-card-hd"><Building2 size={14} /> Company Details</div>
                              <div className="acv-card-bd">
                                <InfoRow label="Company Name" value={records?.company_name} />
                                <InfoRow label="Company Email" value={records?.company_email} />
                                <InfoRow label="Phone" value={records?.phone} />
                                <InfoRow label="Industry" value={records?.company_industory} />
                                <InfoRow label="Employees" value={records?.employee_number} />
                                <InfoRow label="Year Founded" value={records?.year_registration} />
                              </div>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="acv-card h-100">
                              <div className="acv-card-hd"><User size={14} /> Owner Information</div>
                              <div className="acv-card-bd">
                                <InfoRow label="First Name" value={records?.user_first_name} />
                                <InfoRow label="Last Name" value={records?.user_last_name} />
                              </div>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="acv-card h-100">
                              <div className="acv-card-hd"><MapPin size={14} /> Address</div>
                              <div className="acv-card-bd">
                                <InfoRow label="Street Address" value={records?.company_street_address} />
                                <InfoRow label="City" value={records?.company_city} />
                                <InfoRow label="State / Province / District" value={records?.company_state} />
                                <InfoRow label="Postal Code" value={records?.company_postal_code} />
                                <InfoRow label="Country" value={records?.company_country} />
                              </div>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="acv-card h-100">
                              <div className="acv-card-hd"><FileText size={14} /> About</div>
                              <div className="acv-card-bd">
                                <InfoRow label="One-sentence headliner" value={records?.descriptionStep4} />
                                <InfoRow label="What problem are you solving" value={records?.problemStep4} />
                                <InfoRow label="Solution to the Problem" value={records?.solutionStep4} />
                              </div>
                            </div>
                          </div>
                        </div>
                      )}

                      {/* ── INVESTORS TAB ── */}


                      {activeTab === "investors" && (
                        <div className="acv-card">
                          <div className="acv-card-hd"><Users size={14} /> All Investors</div>
                          <div style={{ overflowX: "auto" }}>
                            <table className="acv-table">
                              <thead>
                                <tr>
                                  <th>#</th>
                                  <th>Investor</th>
                                  <th>Email</th>
                                  <th>Phone</th>
                                  <th>Invested</th>
                                  <th>Date</th>
                                  <th>Status</th>
                                </tr>
                              </thead>
                              <tbody>
                                {allinvestment?.length > 0 ? (
                                  allinvestment.map((inv, i) => (
                                    <tr key={inv.id || i}>
                                      <td style={{ color: "#94a3b8", fontSize: 12 }}>{i + 1}</td>
                                      <td>
                                        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                                          <div style={{ width: 32, height: 32, borderRadius: 8, background: "#fff5f5", color: "#ef4444", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 12, flexShrink: 0 }}>
                                            {inv.first_name?.charAt(0) || inv.last_name?.charAt(0) || "?"}
                                          </div>
                                          <span style={{ fontWeight: 600 }}>{inv.first_name} {inv.last_name}</span>
                                        </div>
                                      </td>
                                      <td>{inv.email}</td>
                                      <td>{inv.phone || "—"}</td>
                                      <td style={{ fontWeight: 600, color: "#0f172a" }}>{inv.investment_amount ? (
                                        <CurrencyFormatterAdmin amount={inv.investment_amount} currency={inv.currency} digit={2} />
                                      ) : (
                                        "0.00"
                                      )}</td>
                                      <td style={{ color: "#64748b" }}>{formatDate(inv.created_at) || inv.date || "—"}</td>
                                      <td>
                                        <span className={`pill ${inv.request_confirm === "Yes" ? "pill-green" :
                                          inv.request_confirm === "No" ? "pill-red" :
                                            "pill-gray"
                                          }`}>
                                          {inv.request_confirm === "Yes" ? "Active" :
                                            inv.request_confirm === "No" ? "Pending" :
                                              "N/A"}
                                        </span>
                                      </td>
                                    </tr>
                                  ))
                                ) : (
                                  <tr>
                                    <td colSpan="7" style={{ textAlign: "center", padding: "40px", color: "#94a3b8" }}>
                                      No investors found
                                    </td>
                                  </tr>
                                )}
                              </tbody>
                            </table>
                          </div>
                        </div>
                      )}

                      {/* ── ROUNDS TAB ── */}

                      {activeTab === "rounds" && (
                        <div className="acv-card">
                          <div className="acv-card-hd">
                            <TrendingUp size={14} /> Funding Rounds
                            <span style={{
                              background: "#f1f5f9", color: "#64748b",
                              borderRadius: 20, padding: "1px 8px",
                              fontSize: 11, fontWeight: 700, marginLeft: 4,
                            }}>
                              {companyFundinground.length}
                            </span>
                          </div>

                          <div style={{ overflowX: "auto" }}>
                            <table className="acv-table">
                              <thead>
                                <tr>
                                  <th>#</th>
                                  <th>Round Name</th>
                                  <th>Share Class</th>
                                  <th>Instrument</th>
                                  <th>Round Size</th>
                                  <th>Total Invested</th>
                                  <th>Investors</th>
                                </tr>
                              </thead>
                              <tbody>
                                {companyFundinground.map((r, i) => {
                                  const size = parseFloat(r.roundsize) || 0;
                                  const invested = parseFloat(r.total_invested) || 0;
                                  const pct = size > 0 ? Math.min(Math.round((invested / size) * 100), 100) : 0;
                                  const barColor = pct >= 100 ? "#22c55e" : pct >= 50 ? "#f59e0b" : "#ef4444";

                                  return (
                                    <tr key={r.id}>
                                      {/* # */}
                                      <td style={{ color: "#94a3b8", fontSize: 12 }}>{i + 1}</td>

                                      {/* Round Name */}
                                      <td style={{ fontWeight: 600, color: "#0f172a" }}>
                                        {r.nameOfRound || "—"}
                                      </td>

                                      {/* Share Class */}
                                      <td>
                                        {r.shareClassType
                                          ? <span className={typePill[r.shareClassType] || "pill pill-gray"}>{r.shareClassType}</span>
                                          : <span style={{ color: "#cbd5e1" }}>—</span>
                                        }
                                      </td>

                                      {/* Instrument Type */}
                                      <td>
                                        {r.instrumentType
                                          ? <span className={typePill[r.instrumentType] || "pill pill-purple"}>{r.instrumentType}</span>
                                          : <span style={{ color: "#cbd5e1" }}>—</span>
                                        }
                                      </td>

                                      {/* Round Size (Target) */}
                                      <td style={{ fontFamily: "monospace", fontSize: 12, fontWeight: 600 }}>


                                        <CurrencyFormatterAdmin
                                          amount={fmtMoney(r.roundsize)}
                                          currency={r.currency}
                                          digit={2}
                                        />
                                      </td>

                                      {/* Total Invested + progress bar */}
                                      <td>
                                        <div style={{ fontWeight: 700, color: "#0f172a", fontSize: 13 }}>

                                          <CurrencyFormatterAdmin
                                            amount={fmtMoney(r.total_invested)}
                                            currency={r.currency}
                                            digit={2}
                                          />
                                        </div>
                                        {size > 0 && (
                                          <>
                                            <div style={{
                                              height: 4, background: "#f1f5f9",
                                              borderRadius: 4, marginTop: 4, width: 80,
                                            }}>
                                              <div style={{
                                                height: "100%", width: `${pct}%`,
                                                background: barColor, borderRadius: 4,
                                              }} />
                                            </div>
                                            <div style={{ fontSize: 10, color: "#94a3b8", marginTop: 2 }}>
                                              {pct}% funded
                                            </div>
                                          </>
                                        )}
                                      </td>

                                      {/* Unique Investors — COUNT(DISTINCT investor_id) from backend */}
                                      <td style={{ textAlign: "center", fontWeight: 600 }}>
                                        {r.investor_count ?? "—"}
                                      </td>
                                    </tr>
                                  );
                                })}
                              </tbody>

                              {/* Footer totals */}
                              <tfoot>
                                <tr style={{ background: "#f8fafc" }}>
                                  <td colSpan={4} style={{
                                    fontWeight: 700, padding: "10px 14px",
                                    fontSize: 12, color: "#0f172a",
                                  }}>
                                    Totals
                                  </td>
                                  <td style={{ fontWeight: 700, padding: "10px 14px", fontSize: 12, fontFamily: "monospace" }}>
                                    <CurrencyFormatterAdmin
                                      amount={fmtMoney(companyFundinground.reduce((s, r) => s + (parseFloat(r.roundsize) || 0), 0))}
                                      currency={companyFundinground[0]?.currency || ""}
                                      digit={2}
                                    />
                                  </td>
                                  <td style={{ fontWeight: 700, padding: "10px 14px", fontSize: 12, color: "#ef4444", fontFamily: "monospace" }}>
                                    <CurrencyFormatterAdmin
                                      amount={fmtMoney(companyFundinground.reduce((s, r) => s + (parseFloat(r.total_invested) || 0), 0))}
                                      currency={companyFundinground[0]?.currency || ""}
                                      digit={2}
                                    />
                                  </td>
                                  <td style={{ fontWeight: 700, padding: "10px 14px", fontSize: 12, textAlign: "center" }}>
                                    {companyFundinground.reduce((s, r) => s + (parseInt(r.investor_count) || 0), 0)}

                                  </td>
                                </tr>
                              </tfoot>
                            </table>
                          </div>
                        </div>
                      )}

                      {/* ── CAP TABLE TAB ── */}
                      {activeTab === "captable" && (
                        <div className="acv-card">
                          <div className="acv-card-hd"><PieChart size={14} /> Cap Table</div>
                          <div style={{ overflowX: "auto" }}>
                            <table className="acv-table">
                              <thead>
                                <tr>
                                  <th>#</th>
                                  <th>Shareholder</th>
                                  <th>Share Class</th>
                                  <th>Shares</th>
                                  <th>Ownership %</th>
                                  <th>Price / Share</th>
                                  <th>Date</th>
                                </tr>
                              </thead>
                              <tbody>
                                {STATIC_CAPTABLE.map((row, i) => (
                                  <tr key={i}>
                                    <td style={{ color: "#94a3b8", fontSize: 12 }}>{i + 1}</td>
                                    <td>
                                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                                        <div style={{ width: 30, height: 30, borderRadius: 7, background: "#fff5f5", color: "#ef4444", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 11, flexShrink: 0 }}>
                                          {row.investor.charAt(0)}
                                        </div>
                                        <span style={{ fontWeight: 600 }}>{row.investor}</span>
                                      </div>
                                    </td>
                                    <td>
                                      <span className={`pill ${row.class === "Preferred" ? "pill-blue" : row.class === "Founder" ? "pill-purple" : "pill-gray"}`}>
                                        {row.class}
                                      </span>
                                    </td>
                                    <td style={{ fontFamily: "monospace", fontSize: 12 }}>{row.shares}</td>
                                    <td>
                                      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                                        <div style={{ width: 60, height: 5, background: "#f1f5f9", borderRadius: 4 }}>
                                          <div style={{ height: "100%", width: row.percent, background: "#ef4444", borderRadius: 4 }} />
                                        </div>
                                        <span style={{ fontWeight: 700, color: "#0f172a", fontSize: 12 }}>{row.percent}</span>
                                      </div>
                                    </td>
                                    <td>{row.price}</td>
                                    <td style={{ color: "#64748b" }}>{row.date}</td>
                                  </tr>
                                ))}
                              </tbody>
                              <tfoot>
                                <tr style={{ background: "#f8fafc" }}>
                                  <td colSpan={3} style={{ fontWeight: 700, padding: "10px 14px", fontSize: 12 }}>Total</td>
                                  <td style={{ fontWeight: 700, fontFamily: "monospace", fontSize: 12, padding: "10px 14px" }}>1,000,000</td>
                                  <td style={{ fontWeight: 700, fontSize: 12, padding: "10px 14px" }}>100%</td>
                                  <td colSpan={2} />
                                </tr>
                              </tfoot>
                            </table>
                          </div>
                        </div>
                      )}

                      {/* ── DOCUMENTS TAB ── */}
                      {activeTab === "documents" && (
                        <div className="acv-card">
                          <div className="acv-card-hd"><FolderOpen size={14} /> Documents</div>
                          <div className="acv-card-bd" style={{ paddingTop: 8 }}>
                            {companyDocument && companyDocument.length > 0 ? (
                              companyDocument.map((doc, i) => (
                                <div key={i} className="acv-doc">
                                  <div className="acv-doc-icon" style={{ background: `${docColor[doc.type]}15`, color: docColor[doc.type] }}>
                                    <FileText size={16} />
                                  </div>
                                  <div className="flex-grow-1">
                                    <div className="acv-doc-name">{doc.document_name}</div>
                                    <div className="acv-doc-meta">{formatDate(doc.created_at)}</div>
                                  </div>
                                </div>
                              ))
                            ) : (
                              <div style={{
                                textAlign: "center",
                                padding: "40px 20px",
                                color: "#94a3b8",
                                fontSize: 14
                              }}>
                                <FolderOpen size={32} style={{ marginBottom: 8, opacity: 0.5 }} />
                                <div>No documents found</div>
                              </div>
                            )}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </div>
        </div>
      </div>
    </>
  );
}

export default AdminCompanyView;